sql.where:
coalesce(p.del_flag, '0') = '0'
and p.process_status != '9'

	and p.park_id = #{project.parkId}
	and p.customer_id = #{project.customerId}
	and p.flow_id = #{project.flowId}
	and p.business_id = #{project.businessId}
	and p.business_type = #{project.businessType}
	and p.project_name like concat('%', #{project.projectName}, '%')
	and p.enterprise_name like concat('%', #{project.enterpriseName}, '%')
	and p.process_status = #{project.processStatus}
	and p.process_status != #{project.excludeProcessStatus}

		and (p.applicant = #{project.currentUser} or p.create_by = #{project.currentUser})


		and p.process_status = '1'

			and find_in_set(#{project.currentUser}, replace(coalesce(p.current_node, ''), ' ', '')) > 0



		and exists (
			select 1
			from biz_approval_log al_done
			where al_done.project_id = p.project_id
			  and al_done.operator_name = #{project.currentUser}
			  and al_done.action_type in ('APPROVE', 'REJECT', 'TRANSFER')
		)


		and (
			exists (
				select 1
				from biz_approval_node an_cc
				where an_cc.flow_id = p.flow_id
				  and find_in_set(#{project.currentUser}, replace(coalesce(an_cc.cc_users, ''), ' ', '')) > 0
			)
			or exists (
				select 1
				from biz_approval_log al_cc
				where al_cc.project_id = p.project_id
				  and find_in_set(#{project.currentUser}, replace(coalesce(al_cc.cc_users, ''), ' ', '')) > 0
			)
		)

